using namespace std;

class Solution {
private:
    static string convertToBase(int num, int base) {
        if (num == 0) {
            return "0";
        }
        string result;
        while (num > 0) {
            int remainder = num % base;
            char c;
            if (remainder < 10) {
                c = '0' + remainder;
            } else {
                c = 'A' + (remainder - 10);
            }
            result = c + result;
            num = num / base;
        }
        return result;
    }
public:
    string concatHex36(int n) {
        int n2 = n * n;
        int n3 = n * n * n;
        string hex = convertToBase(n2, 16);
        string base36 = convertToBase(n3, 36);
        return hex + base36;
    }
};

